var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"적들이 너무 많아서 방어선을 유지하긴 힘들어요.","JPN":"敵が多すぎて、防衛線を維持するのが困難です。","ENG":"There’s too many of them for us to hold a line of defense.","TWN":"敵人太多了，很難維持防線。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"일단 두 분을 호위하면서 이곳에서 빠져나가는 걸 최우선 목표로 삼겠습니다.","JPN":"まずはお2人を護衛しながら、ここを脱出することを最優先目標にします。","ENG":"Our priority will be to escort you two out of here.","TWN":"我們會優先護送兩位離開這裡。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그건 기각.","JPN":"それは却下。","ENG":"Denied.","TWN":"駁回。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"Sorry?","TWN":"什麼？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"말했지? 이 로스트 쉽은 합중국의 안보에 매우 중요한 물건이야.","JPN":"言ったわよね？　このロストシップは合衆国の安全保障にとても重要な物なのよ。","ENG":"Like I said... The Lost Ship is an item of paramount importance for my country’s national security.","TWN":"我說過了吧？這艘失落艦船對於合眾國的安全保障非常重要。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"이 정도 습격에 포기할 거면 처음부터 시작도 안 했어.","JPN":"この程度の襲撃で断念するくらいなら、最初から始めさえしなかったわ。","ENG":"I wouldn’t have even bothered to come here if an attack like this was enough to stop me.","TWN":"如果只因為這點突襲就放棄，那我當初就不會做這件事。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"하지만 적이.......","JPN":"ですが、敵が……","ENG":"But the enemies...","TWN":"但是敵人……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"미안하지만, 내 커리어에 작전 실패나 기록 같은 건 한 번도 없어.","JPN":"悪いけど、アタシのキャリアに作戦失敗の記録なんて1つもないの。","ENG":"Sorry, but I’ve never failed a mission in my entire career.","TWN":"不好意思，在我的職業生涯中，作戰失敗的記錄連一次都沒有。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"이번에도 마찬가지야. 합중국의 모토는 언제나 Power Overwhelming!","JPN":"今回も同じよ。合衆国のモットーはいつもPower Overwhelming！","ENG":"I don’t plan to start now either. I’ll show ‘em how things are done in the States!","TWN":"這次也一樣。合眾國的座右銘是“Power Overwhelming”！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"이미 선빵을 맞은 이상 많으면 많은 대로, 적으면 적은 대로 모두 박살을 내 준다!","JPN":"先手を打たれた以上、敵が多ければ多いなりに、少なければ少ないなりにすべて木っ端微塵にする！","ENG":"They might have thrown the first punch, but they're all gonna go down now! No matter how many there are!","TWN":"既然都被捲入這場戰鬥了，無論敵人有多少，我都會將它們全部消滅！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"어....... 음....... 그, 용기는 가상합니다만.......","JPN":"あ……えっと……その勇気は素晴らしいですが……","ENG":"Err... Umm... As admirable as your valor is...","TWN":"呃……嗯……我很欣賞妳的勇氣……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그리고....... 두리안 버터맨을 그렇게 비웃고 혼자 왔는데, 여기서 도망쳤다간 나중에 마리아 아줌마에게 대체 뭔 소리를 들을지......","JPN":"それに……ドリアンバターマンのことをあんなにバカにして1人で来たのに、ここで逃げ出したら、マリアおばさんに何て言われるか……","ENG":"Besides... After all that trash talk about that sleazeball, Maria’s gonna give me hell if I bail out like this...","TWN":"而且……在嘲笑完杜力安是個小白臉後一個人來到這裡，要是現在逃跑的話，真不知道瑪麗亞大嬸會說些什麼……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"음? 뭐라고 하셨죠?","JPN":"はい？ 今なんとおっしゃいました？","ENG":"Huh? What was that?","TWN":"嗯？妳剛說什麼？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아, 아무것도 아니야! 혼잣말이야, 혼잣말!","JPN":"な、何でもないわ！　ひとりごとよ、ひとりごと！","ENG":"N-nothing! Just mumbling to myself, that’s all!","TWN":"沒、沒什麼！我在自言自語而已，自言自語啦！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"어쨌든 로스트 쉽을 회수하기 위해 출발한 지원군이 이미 이쪽으로 움직이고 있을 거야. 그때까지만 버티면 돼.","JPN":"とにかくロストシップ回収のために出発した支援軍は、すでにこっちに向かって移動していると思うわ。だから、到着するまでなんとか耐え抜けばいいの。","ENG":"Anyway, backup should be on its way to retrieve the Lost Ship. We just need to hang on till then.","TWN":"總之，來回收失落艦船的援軍已經在路上了，只要撐到那時候就可以了。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"가능하겠지? 아줌마?","JPN":"できるわよね、おばさん？","ENG":"That’s doable, right? Old lady?","TWN":"可以做到吧？大嬸？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......후우.","JPN":"……ふう。","ENG":"*Sigh*","TWN":"呼……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"뭐, 돈 낸 사람이 까라면 까는 거죠.","JPN":"まあ、スポンサーの意向なら従うのみです。","ENG":"Sure I guess. You’re the one who's writing our paychecks.","TWN":"好吧，出錢的人說了算。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"서윤 양. 알트 소대를 소집하세요.","JPN":"シズカさん、アルト小隊を招集してください。","ENG":"Seo Yoon. Assemble the ALT Squad.","TWN":"徐芸小姐，請召集阿爾特小隊。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그리고 그 뭐였더라? 메이슨 어쩌고 하는 떨거지들도 다 모이라고 하세요.","JPN":"それから、あれ何でしたっけ？　メイソンなんとかっていう人たちも全員集まるよう言ってください。","ENG":"And oh... what did they call themselves again? Get that Mason and the stooges or whatever to come as well.","TWN":"還有把那個什麼來著？叫梅森的還有什麼一夥的都叫過來吧。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"전열을 정비한 후 반격을 시작합니다.","JPN":"戦列を整備した後、反撃を開始します。","ENG":"Once we regroup, we’ll begin the retaliation.","TWN":"整頓好戰鬥隊伍後，開始反擊。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"괜찮으시겠어요, 부사장님? 실비아 양은 그렇다 쳐도 부사장님은 전투 요원도 아닌데.......","JPN":"大丈夫ですか、副社長？　シルビアさんならともかく、副社長は戦闘要員ではないのに……","ENG":"You sure about that ma’am? I mean, Agent Sylvia can probably handle herself, but you're not a combat operative...","TWN":"沒關係嗎，副總？希爾維亞就算了，但副總又不是戰鬥人員……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"후후. 이것 참.","JPN":"ふふっ、まったく。","ENG":"Haha. My, oh my.","TWN":"呵呵，這還真是。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"살다 보니 새파란 후배들에게 걱정을 받는 날도 오는군요.","JPN":"まさか若い後輩たちに心配される日が来るなんてね。","ENG":"I never knew the day would come when someone generations my junior would get concerned for me.","TWN":"沒想到在我活著的時候，會有被後輩們擔心的一天。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이래 봬도 제가 소싯적에는 꽤 날리던 몸입니다.","JPN":"こう見えても若いころは腕を鳴らしていましたので。","ENG":"Believe it or not, I used to pack quite a punch myself back in the day.","TWN":"別看我這樣，我年輕時身手可是很好的，"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"제 몸 하나 정도는 충분히 지킬 수 있으니 걱정할 필요 없어요. 서윤 양.","JPN":"自分1人くらいなら充分守れるので、心配はいりませんよ、シズカさん。","ENG":"I can handle myself just fine, so don’t worry about me. Seo Yoon.","TWN":"要照顧自己完全沒問題。不用擔心，徐芸小姐。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"아, 알겠습니다.","JPN":"りょ、了解しました。","ENG":"U-understood.","TWN":"好的。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};